import { useCallback, useEffect, useState } from 'react'
import { getActivity } from '../../notifications/services/notificationService'

export function useActivity(filters = {}) {
  const [activity, setActivity] = useState([])
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(true)

  const loadActivity = useCallback(async () => {
    setIsLoading(true)
    setError('')

    try {
      setActivity(await getActivity(filters))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }, [filters])

  useEffect(() => {
    loadActivity()
  }, [loadActivity])

  return {
    activity,
    error,
    isLoading,
    loadActivity,
  }
}

import { useEffect, useState } from 'react'
import {
  createQuestion,
  createQuestionSet,
  getQuestionSets,
  updateQuestionSet,
} from '../services/analyticsService'

export function QuestionSetManager() {
  const [sets, setSets] = useState([])
  const [activeSetId, setActiveSetId] = useState('')
  const [setForm, setSetForm] = useState({ title: '', description: '' })
  const [questionForm, setQuestionForm] = useState({ prompt: '', questionType: 'rating_scale' })
  const [error, setError] = useState('')

  async function loadSets() {
    setSets(await getQuestionSets())
  }

  useEffect(() => {
    loadSets().catch((loadError) => setError(loadError.message))
  }, [])

  async function saveSet(event) {
    event.preventDefault()
    setError('')
    try {
      const next = await createQuestionSet(setForm)
      setSets((current) => [next, ...current])
      setActiveSetId(next.id)
      setSetForm({ title: '', description: '' })
    } catch (saveError) {
      setError(saveError.message)
    }
  }

  async function saveQuestion(event) {
    event.preventDefault()
    setError('')
    try {
      await createQuestion({ ...questionForm, questionSetId: activeSetId, options: [], position: 0, isRequired: true })
      await loadSets()
      setQuestionForm({ prompt: '', questionType: 'rating_scale' })
    } catch (saveError) {
      setError(saveError.message)
    }
  }

  async function archiveSet(id) {
    await updateQuestionSet(id, { isArchived: true })
    setSets((current) => current.filter((set) => set.id !== id))
  }

  return (
    <section className="analytics-panel">
      <h3>Learning Evaluation Questions</h3>
      {error ? <p className="form-error">{error}</p> : null}
      <form className="analytics-form" onSubmit={saveSet}>
        <input value={setForm.title} onChange={(event) => setSetForm((current) => ({ ...current, title: event.target.value }))} placeholder="Question set title" required />
        <input value={setForm.description} onChange={(event) => setSetForm((current) => ({ ...current, description: event.target.value }))} placeholder="Description" />
        <button className="primary-button" type="submit">Create set</button>
      </form>
      <div className="analytics-list">
        {sets.map((set) => (
          <article className="analytics-row" key={set.id}>
            <button type="button" onClick={() => setActiveSetId(set.id)}>{set.title}</button>
            <span>{set.questions.length} questions</span>
            <button type="button" onClick={() => archiveSet(set.id)}>Archive</button>
          </article>
        ))}
      </div>
      {activeSetId ? (
        <form className="analytics-form" onSubmit={saveQuestion}>
          <input value={questionForm.prompt} onChange={(event) => setQuestionForm((current) => ({ ...current, prompt: event.target.value }))} placeholder="Question" required />
          <select value={questionForm.questionType} onChange={(event) => setQuestionForm((current) => ({ ...current, questionType: event.target.value }))}>
            <option value="rating_scale">Rating scale</option>
            <option value="multiple_choice">Multiple choice</option>
            <option value="short_answer">Short answer</option>
            <option value="long_answer">Long answer</option>
          </select>
          <button className="secondary-button" type="submit">Add question</button>
        </form>
      ) : null}
    </section>
  )
}

import { createContext, useCallback, useEffect, useMemo, useState } from 'react'
import { useAuth } from '../../auth/hooks/useAuth'
import { getAnalytics } from '../services/analyticsService'

export const AnalyticsContext = createContext(null)

export function AnalyticsProvider({ children }) {
  const { user } = useAuth()
  const [analytics, setAnalytics] = useState(null)
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(true)

  const loadAnalytics = useCallback(async (filters = {}) => {
    if (!user?.id) return null
    setIsLoading(true)
    setError('')

    try {
      const data = await getAnalytics(filters)
      setAnalytics(data)
      return data
    } catch (loadError) {
      setError(loadError.message)
      return null
    } finally {
      setIsLoading(false)
    }
  }, [user?.id])

  useEffect(() => {
    loadAnalytics()
  }, [loadAnalytics])

  const value = useMemo(() => ({
    analytics,
    error,
    isLoading,
    loadAnalytics,
  }), [analytics, error, isLoading, loadAnalytics])

  return <AnalyticsContext.Provider value={value}>{children}</AnalyticsContext.Provider>
}

import { useCallback, useEffect, useState } from 'react'
import { supabase } from '../../../lib/supabase/client'
import {
  createAnnouncement,
  deleteAnnouncement,
  getClassAnnouncements,
  updateAnnouncement,
} from '../services/announcementService'

function normalizeRealtimeAnnouncement(row) {
  return {
    id: row.id,
    classId: row.class_id,
    authorId: row.author_id,
    title: row.title,
    body: row.body,
    isPinned: row.is_pinned,
    publishedAt: row.published_at,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  }
}

function sortAnnouncements(items) {
  return [...items].sort((a, b) => {
    if (a.isPinned !== b.isPinned) return a.isPinned ? -1 : 1
    return new Date(b.publishedAt) - new Date(a.publishedAt)
  })
}

export function useAnnouncements(classId, initialAnnouncements = []) {
  const [announcements, setAnnouncements] = useState(initialAnnouncements)
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(false)

  const loadAnnouncements = useCallback(async () => {
    if (!classId) return
    setIsLoading(true)
    setError('')

    try {
      setAnnouncements(await getClassAnnouncements(classId))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }, [classId])

  useEffect(() => {
    setAnnouncements(initialAnnouncements)
  }, [initialAnnouncements])

  useEffect(() => {
    loadAnnouncements()
  }, [loadAnnouncements])

  useEffect(() => {
    if (!classId) return undefined

    const channel = supabase
      .channel(`class:${classId}:announcements`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'announcements',
          filter: `class_id=eq.${classId}`,
        },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            const announcement = normalizeRealtimeAnnouncement(payload.new)
            setAnnouncements((current) => sortAnnouncements([
              announcement,
              ...current.filter((item) => item.id !== announcement.id),
            ]))
          }

          if (payload.eventType === 'UPDATE') {
            const announcement = normalizeRealtimeAnnouncement(payload.new)
            setAnnouncements((current) => sortAnnouncements(
              current.map((item) => item.id === announcement.id ? announcement : item),
            ))
          }

          if (payload.eventType === 'DELETE') {
            setAnnouncements((current) => current.filter((item) => item.id !== payload.old.id))
          }
        },
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [classId])

  const saveNewAnnouncement = useCallback(async (payload) => {
    const announcement = await createAnnouncement(payload)
    setAnnouncements((current) => sortAnnouncements([
      announcement,
      ...current.filter((item) => item.id !== announcement.id),
    ]))
    return announcement
  }, [])

  const saveAnnouncement = useCallback(async (id, payload) => {
    const announcement = await updateAnnouncement(id, payload)
    setAnnouncements((current) => sortAnnouncements(
      current.map((item) => item.id === id ? announcement : item),
    ))
    return announcement
  }, [])

  const removeAnnouncement = useCallback(async (id) => {
    await deleteAnnouncement(id)
    setAnnouncements((current) => current.filter((item) => item.id !== id))
  }, [])

  return {
    announcements,
    error,
    isLoading,
    loadAnnouncements,
    removeAnnouncement,
    saveAnnouncement,
    saveNewAnnouncement,
  }
}

