export function GroupCreationDialog({
  open,
  onOpenChange,
  projects,
  defaultProjectId = '',
  onCreateManual,
  onPreviewCreation,
  onGenerateCreation,
  onUpdateFormationStatus,
}) {
  const [mode, setMode] = useState('manual')
  const [error, setError] = useState('')
  const [isPreviewing, setIsPreviewing] = useState(false)
  const [isSaving, setIsSaving] = useState(false)
  const [manualForm, setManualForm] = useState({ projectId: '', name: '', description: '' })
  const [state, setState] = useState({
    random: { projectId: '', preview: null },
    similar_performance: { projectId: '', preview: null },
    student_formed: { projectId: '', preview: null },
  })

  const groupProjects = useMemo(() => projects.filter((project) => project.workMode === 'group'), [projects])

  useEffect(() => {
    if (!open) return
    const firstProjectId = defaultProjectId || groupProjects[0]?.id || ''
    setManualForm((current) => ({ ...current, projectId: current.projectId || firstProjectId }))
    setState((current) => ({
      random: { ...current.random, projectId: current.random.projectId || firstProjectId },
      similar_performance: { ...current.similar_performance, projectId: current.similar_performance.projectId || firstProjectId },
      student_formed: { ...current.student_formed, projectId: current.student_formed.projectId || firstProjectId },
    }))
  }, [defaultProjectId, groupProjects, open])

  function updateModeProject(modeKey, projectId) {
    setState((current) => ({
      ...current,
      [modeKey]: { ...current[modeKey], projectId, preview: null },
    }))
  }

  async function handleManualSubmit(event) {
    event.preventDefault()
    setError('')
    try {
      await onCreateManual({
        projectId: manualForm.projectId,
        name: manualForm.name,
        description: manualForm.description || null,
      })
      onOpenChange(false)
    } catch (saveError) {
      setError(saveError.message)
    }
  }

  async function handlePreview(modeKey, projectId) {
    if (!projectId) return
    setError('')
    setIsPreviewing(true)
    try {
      const preview = await onPreviewCreation({ projectId, mode: modeKey })
      setState((current) => ({
        ...current,
        [modeKey]: { projectId, preview },
      }))
    } catch (previewError) {
      setError(previewError.message)
    } finally {
      setIsPreviewing(false)
    }
  }

  async function handleSave(modeKey, projectId, preview) {
    if (!preview?.groups?.length) return
    setError('')
    setIsSaving(true)
    try {
      const payload = {
        projectId,
        mode: modeKey,
        groups: preview.groups,
      }
      if (modeKey === 'student_formed') payload.formationStatus = 'open'
      await onGenerateCreation(payload)
      onOpenChange(false)
    } catch (saveError) {
      setError(saveError.message)
    } finally {
      setIsSaving(false)
    }
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="group-creation-dialog">
        <DialogHeader>
          <DialogTitle>Create Groups</DialogTitle>
          <DialogDescription>Manual, random, similar performance, and student-formed grouping.</DialogDescription>
        </DialogHeader>

        <Tabs value={mode} onValueChange={setMode} className="flex flex-col gap-4">
          <TabsList className="grid w-full grid-cols-2 gap-2 md:grid-cols-4">
            {MODES.map((item) => (
              <TabsTrigger key={item.key} value={item.key}>{item.label}</TabsTrigger>
            ))}
          </TabsList>

          <TabsContent value="manual">
            <form className="flex flex-col gap-4" onSubmit={handleManualSubmit}>
              <FieldGroup className="grid gap-4">
                <Field>
                  <FieldLabel htmlFor="manual-project">Project</FieldLabel>
                  <Select id="manual-project" value={manualForm.projectId} onChange={(event) => setManualForm((current) => ({ ...current, projectId: event.target.value }))}>
                    <option value="">Select project</option>
                    {groupProjects.map((project) => (
                      <option key={project.id} value={project.id}>{project.title}</option>
                    ))}
                  </Select>
                </Field>
                <Field>
                  <FieldLabel htmlFor="manual-name">Group name</FieldLabel>
                  <Input id="manual-name" value={manualForm.name} onChange={(event) => setManualForm((current) => ({ ...current, name: event.target.value }))} />
                </Field>
                <Field>
                  <FieldLabel htmlFor="manual-description">Description</FieldLabel>
                  <Textarea id="manual-description" rows="4" value={manualForm.description} onChange={(event) => setManualForm((current) => ({ ...current, description: event.target.value }))} />
                </Field>
              </FieldGroup>
              {error ? <p className="form-error">{error}</p> : null}
              <DialogFooter>
                <Button type="submit">Create Group</Button>
                <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>Cancel</Button>
              </DialogFooter>
            </form>
          </TabsContent>

          {MODES.filter((item) => item.key !== 'manual').map((item) => (
            <TabsContent key={item.key} value={item.key}>
              <ModePanel
                active={mode === item.key}
                description={item.description}
                mode={item.key}
                onPreview={handlePreview}
                onSave={handleSave}
                onUpdateStatus={onUpdateFormationStatus}
                preview={state[item.key].preview}
                projectId={state[item.key].projectId}
                projects={projects}
                setProjectId={(projectId) => updateModeProject(item.key, projectId)}
                error={error}
                isPreviewing={isPreviewing}
                isSaving={isSaving}
                memberCount={groupProjects.find((project) => project.id === state[item.key].projectId)?.memberCount}
              />
            </TabsContent>
          ))}
        </Tabs>
      </DialogContent>
    </Dialog>
  )
}

import { useCallback, useEffect, useState } from 'react'
import {
  addGroupMember,
  createGroup,
  generateGroupCreation,
  getEligibleGroupMembers,
  getAvailableGroups,
  getGroups,
  previewGroupCreation,
  joinGroup,
  updateStudentFormedGroupsStatus,
  updateGroup,
  updateGroupMember,
} from '../services/groupService'

export function useGroups(projectId) {
  const [groups, setGroups] = useState([])
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(true)

  const loadGroups = useCallback(async () => {
    setIsLoading(true)
    setError('')

    try {
      setGroups(await getGroups(projectId))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }, [projectId])

  useEffect(() => {
    loadGroups()
  }, [loadGroups])

  const addGroup = useCallback(async (payload) => {
    const group = await createGroup(payload)
    setGroups((current) => [group, ...current])
    return group
  }, [])

  const join = useCallback(async (groupId) => {
    const group = await joinGroup(groupId)
    setGroups((current) => {
      const exists = current.some((item) => item.id === group.id)
      return exists ? current.map((item) => item.id === group.id ? group : item) : [group, ...current]
    })
    return group
  }, [])

  const saveGroup = useCallback(async (groupId, payload) => {
    const group = await updateGroup(groupId, payload)
    setGroups((current) => current.map((item) => item.id === group.id ? group : item))
    return group
  }, [])

  const saveMember = useCallback(async (groupId, userId, payload) => {
    const group = await updateGroupMember(groupId, userId, payload)
    setGroups((current) => current.map((item) => item.id === group.id ? group : item))
    return group
  }, [])

  const loadEligibleMembers = useCallback((groupId) => getEligibleGroupMembers(groupId), [])

  const addMember = useCallback(async (groupId, userId) => {
    const group = await addGroupMember(groupId, userId)
    setGroups((current) => current.map((item) => item.id === group.id ? group : item))
    return group
  }, [])

  const previewCreation = useCallback((payload) => previewGroupCreation(payload), [])
  const generateCreation = useCallback(async (payload) => {
    const createdGroups = await generateGroupCreation(payload)
    setGroups((current) => [...createdGroups, ...current])
    return createdGroups
  }, [])
  const loadAvailableGroups = useCallback((filters) => getAvailableGroups(filters), [])
  const updateFormationStatus = useCallback(async (payload) => {
    const updatedGroups = await updateStudentFormedGroupsStatus(payload)
    setGroups((current) => {
      const byId = new Map(updatedGroups.map((group) => [group.id, group]))
      return current.map((item) => byId.get(item.id) ?? item)
    })
    return updatedGroups
  }, [])

  return {
    addMember,
    addGroup,
    generateCreation,
    error,
    groups,
    isLoading,
    join,
    loadGroups,
    loadAvailableGroups,
    loadEligibleMembers,
    previewCreation,
    saveGroup,
    saveMember,
    updateFormationStatus,
  }
}

import { useEffect, useMemo, useState } from 'react'
import { useSearchParams } from 'react-router-dom'
import { USER_ROLES } from '../../auth/constants/roles'
import { useAuth } from '../../auth/hooks/useAuth'
import { useClasses } from '../../classes/hooks/useClasses'
import { useProjects } from '../../projects/hooks/useProjects'
import { GroupCard } from '../components/GroupCard'
import { GroupCreationDialog } from '../components/GroupCreationDialog'
import { StudentAvailableGroupsPanel } from '../components/StudentAvailableGroupsPanel'
