        <p className="muted-copy">Current active members: {activeCount}</p>
        {error ? <p className="form-error">{error}</p> : null}
        <button className="primary-button" type="submit" disabled={isSaving}>{isSaving ? 'Saving...' : 'Save group'}</button>
      </form>
