function AddGroupMemberModal({ group, loadEligibleMembers, onAdd, onClose, onSave }) {
  const activeCount = (group.members ?? []).filter((member) => member.status !== 'removed').length
  const currentLimit = group.memberLimit ?? group.project?.memberCount ?? 1
  const [eligibleMembers, setEligibleMembers] = useState([])
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(true)
  const [isSaving, setIsSaving] = useState(false)
  const [memberLimit, setMemberLimit] = useState(currentLimit)
  const [search, setSearch] = useState('')
  const [userId, setUserId] = useState('')
  const filteredMembers = useMemo(() => {
    const term = search.trim().toLowerCase()
    if (!term) return eligibleMembers
    return eligibleMembers.filter((member) => {
      const name = member.displayName ?? ''
      const email = member.email ?? ''
      return `${name} ${email}`.toLowerCase().includes(term)
    })
  }, [eligibleMembers, search])

  useEffect(() => {
    let isMounted = true
    setIsLoading(true)
    setError('')
    loadEligibleMembers(group.id)
      .then((members) => {
        if (!isMounted) return
        setEligibleMembers(members)
        setUserId(members[0]?.userId ?? '')
      })
      .catch((loadError) => {
        if (isMounted) setError(loadError.message)
      })
      .finally(() => {
        if (isMounted) setIsLoading(false)
      })
    return () => {
      isMounted = false
    }
  }, [group.id, loadEligibleMembers])

  useEffect(() => {
    if (!filteredMembers.some((member) => member.userId === userId)) {
      setUserId(filteredMembers[0]?.userId ?? '')
    }
  }, [filteredMembers, userId])

  async function handleSubmit(event) {
    event.preventDefault()
    setError('')
    setIsSaving(true)
    try {
      const nextLimit = Number(memberLimit)
      if (Number.isFinite(nextLimit) && nextLimit !== currentLimit) {
        await onSave(group.id, { memberLimit: nextLimit })
      }
      await onAdd(group.id, userId)
      onClose()
    } catch (saveError) {
      setError(saveError.message)
    } finally {
      setIsSaving(false)
    }
  }

  return (
    <div className="modal-backdrop">
      <form className="modal-panel group-manage-modal" onSubmit={handleSubmit}>
        <div className="task-section-heading">
          <div>
            <p className="eyebrow">Group</p>
            <h3>Add member</h3>
          </div>
          <button className="secondary-button" type="button" onClick={onClose}>Close</button>
        </div>
        {isLoading ? <p className="muted-copy">Loading eligible members...</p> : null}
        <label className="form-field" htmlFor="eligibleMemberSearch">
          <span>Search student</span>
          <input
            id="eligibleMemberSearch"
            placeholder="Search by name or email"
            value={search}
            onChange={(event) => setSearch(event.target.value)}
            disabled={isLoading || eligibleMembers.length === 0}
          />
        </label>
        <label className="form-field" htmlFor="eligibleMember">
          <span>Member</span>
          <select id="eligibleMember" required value={userId} onChange={(event) => setUserId(event.target.value)} disabled={isLoading || filteredMembers.length === 0}>
            {filteredMembers.map((member) => (
              <option key={member.userId} value={member.userId}>{member.displayName}</option>
            ))}
          </select>
        </label>
        <label className="form-field" htmlFor="addGroupMemberLimit">
          <span>Member count</span>
          <input
            id="addGroupMemberLimit"
            min={Math.max(1, activeCount)}
            required
            type="number"
            value={memberLimit}
            onChange={(event) => setMemberLimit(event.target.value)}
          />
        </label>
        <p className="muted-copy">Active members: {activeCount}. Current limit: {currentLimit}. Increase this when adding beyond the project limit.</p>
        {!isLoading && eligibleMembers.length > 0 && filteredMembers.length === 0 ? <p className="muted-copy">No matching students.</p> : null}
        {!isLoading && eligibleMembers.length === 0 ? <p className="muted-copy">No eligible class members available.</p> : null}
        {error ? <p className="form-error">{error}</p> : null}
        <button className="primary-button" type="submit" disabled={isSaving || !userId}>{isSaving ? 'Adding...' : 'Add member'}</button>
      </form>
    </div>
  )
}

function getClassLabel(classItem) {
  if (!classItem) return 'Class'
  return classItem.title ?? classItem.name ?? 'Class'
}

export function GroupsPage() {
  const [searchParams] = useSearchParams()
  const { role } = useAuth()
  const { classes, isLoading: isClassesLoading } = useClasses()
  const { projects, isLoading: isProjectsLoading } = useProjects()
  const {
    addGroup,
    addMember,
    error,
    generateCreation,
    groups,
    isLoading,
    join,
    loadAvailableGroups,
    loadEligibleMembers,
    previewCreation,
    saveGroup,
    updateFormationStatus,
  } = useGroups()

  const [createOpen, setCreateOpen] = useState(false)
  const [managedGroup, setManagedGroup] = useState(null)
  const [memberGroup, setMemberGroup] = useState(null)
  const [notice, setNotice] = useState('')
  const [availableGroups, setAvailableGroups] = useState([])
  const [availableLoading, setAvailableLoading] = useState(false)
  const [availableError, setAvailableError] = useState('')
  const [studentFilters, setStudentFilters] = useState({
    classId: searchParams.get('classId') ?? '',
  })
  const [filters, setFilters] = useState({
    classId: '',
    projectId: searchParams.get('projectId') ?? '',
    search: '',
    section: '',
  })

  const isStudent = role === USER_ROLES.STUDENT
  const isProfessor = role === USER_ROLES.PROFESSOR
  const activeJoinedGroups = useMemo(
    () => groups.filter((group) => (group.members ?? []).some((member) => member.status === 'active')),
    [groups],
  )
  const hasJoinedGroup = activeJoinedGroups.length > 0
  const groupProjects = useMemo(
    () => projects.filter((project) => project.workMode === 'group'),
    [projects],
  )
  const classOptions = useMemo(() => classes.filter((item) => item.id), [classes])
  const sectionOptions = useMemo(() => [...new Set(classOptions.map((item) => item.section).filter(Boolean))], [classOptions])

  useEffect(() => {
    const projectId = searchParams.get('projectId') ?? ''
    setFilters((current) => (current.projectId === projectId ? current : { ...current, projectId }))
  }, [searchParams])

  useEffect(() => {
    if (!isStudent) return
    if (!studentFilters.classId && classOptions[0]?.id) {
      setStudentFilters((current) => ({ ...current, classId: current.classId || classOptions[0].id }))
    }
  }, [classOptions, isStudent, studentFilters.classId])

  useEffect(() => {
    if (!isStudent) return
    let cancelled = false

    async function load() {
      if (!studentFilters.classId || hasJoinedGroup) {
        setAvailableGroups([])
        setAvailableError('')
        return
      }

      setAvailableLoading(true)
      setAvailableError('')
      try {
        const result = await loadAvailableGroups({ classId: studentFilters.classId })
        if (!cancelled) setAvailableGroups(result)
      } catch (loadError) {
        if (!cancelled) setAvailableError(loadError.message)
      } finally {
        if (!cancelled) setAvailableLoading(false)
      }
    }

    load()
    return () => {
      cancelled = true
    }
  }, [hasJoinedGroup, isStudent, loadAvailableGroups, studentFilters.classId])

  const visibleGroups = useMemo(() => {
    const query = filters.search.trim().toLowerCase()
    return groups.filter((group) => {
      const matchesClass = !filters.classId || group.classId === filters.classId
      const matchesProject = !filters.projectId || group.projectId === filters.projectId
      const matchesSection = !filters.section || group.class?.section === filters.section
      const matchesSearch = !query || [
        group.name,
        group.description,
        group.project?.title,
        ...(group.members ?? []).map((member) => member.displayName),
      ].some((value) => value?.toLowerCase().includes(query))

      return matchesClass && matchesProject && matchesSection && matchesSearch
    })
  }, [filters.classId, filters.projectId, filters.search, filters.section, groups])

  const groupedByClass = useMemo(() => visibleGroups.reduce((map, group) => {
    const key = group.classId ?? 'none'
    const rows = map.get(key) ?? {
      className: `${group.class?.name ?? 'Class'}${group.class?.section ? ` - ${group.class.section}` : ''}`,
      groups: [],
    }
    rows.groups.push(group)
    map.set(key, rows)
    return map
  }, new Map()), [visibleGroups])

  async function handleCreate(payload) {
    await addGroup(payload)
    setNotice('Group created.')
    setCreateOpen(false)
  }

  async function handleJoin(groupId) {
    await join(groupId)
    setNotice('Joined group.')
  }

  async function handleLock(groupId, isLocked) {
    await saveGroup(groupId, { isLocked })
    setNotice(isLocked ? 'Group locked.' : 'Group unlocked.')
  }

  async function handleManageGroup(groupId, payload) {
    await saveGroup(groupId, payload)
    setNotice('Group updated.')
  }

  async function handleAddMember(groupId, userId) {
    await addMember(groupId, userId)
    setNotice('Member added.')
  }

  if (isLoading || isClassesLoading || isProjectsLoading) return <div className="route-state">Loading groups...</div>

  return (
    <section className="module-page groups-page">
      <div className="module-header">
        <div>
          <p className="eyebrow">{isProfessor ? 'Professor' : 'Student'}</p>
          <h2>Groups</h2>
          <p>{isProfessor ? 'Review and manage all project groups.' : 'Create, join, and manage your project group.'}</p>
        </div>
        {isProfessor ? (
          <button className="primary-button" type="button" onClick={() => setCreateOpen(true)}>
            Create Groups
          </button>
        ) : null}
      </div>

      {error ? <p className="form-error">{error}</p> : null}
      {availableError ? <p className="form-error">{availableError}</p> : null}
      {notice ? <p className="form-success">{notice}</p> : null}

      <GroupCreationDialog
        open={createOpen}
        onOpenChange={setCreateOpen}
        projects={groupProjects}
        defaultProjectId={filters.projectId}
        onCreateManual={handleCreate}
        onPreviewCreation={previewCreation}
        onGenerateCreation={generateCreation}
        onUpdateFormationStatus={updateFormationStatus}
      />

      {managedGroup ? (
        <ManageGroupModal
          group={managedGroup}
          onClose={() => setManagedGroup(null)}
          onSave={handleManageGroup}
        />
      ) : null}

      {memberGroup ? (
        <AddGroupMemberModal
          group={memberGroup}
          loadEligibleMembers={loadEligibleMembers}
          onAdd={handleAddMember}
          onClose={() => setMemberGroup(null)}
          onSave={handleManageGroup}
        />
      ) : null}

      {isStudent ? (
        <StudentAvailableGroupsPanel
          classes={classes}
          availableGroups={availableGroups}
          joinedGroups={activeJoinedGroups}
          filters={studentFilters}
          setFilters={setStudentFilters}
          isLoading={availableLoading}
          error={availableError}
          onJoin={handleJoin}
        />
      ) : null}

      {isProfessor ? (
        <>
          <div className="group-filter-bar">
            <label className="form-field" htmlFor="groupProjectFilter">
              <span>Project</span>
              <select id="groupProjectFilter" value={filters.projectId} onChange={(event) => setFilters((current) => ({ ...current, projectId: event.target.value }))}>
                <option value="">All projects</option>
                {groupProjects.map((project) => (
                  <option key={project.id} value={project.id}>{project.title}</option>
                ))}
              </select>
            </label>
            <label className="form-field" htmlFor="groupClassFilter">
              <span>Class</span>
              <select id="groupClassFilter" value={filters.classId} onChange={(event) => setFilters((current) => ({ ...current, classId: event.target.value }))}>
                <option value="">All classes</option>
                {classOptions.map((classItem) => (
                  <option key={classItem.id} value={classItem.id}>{getClassLabel(classItem)}</option>
                ))}
              </select>
            </label>
            <label className="form-field" htmlFor="groupSectionFilter">
              <span>Section</span>
              <select id="groupSectionFilter" value={filters.section} onChange={(event) => setFilters((current) => ({ ...current, section: event.target.value }))}>
                <option value="">All sections</option>
                {sectionOptions.map((section) => (
                  <option key={section} value={section}>{section}</option>
                ))}
              </select>
            </label>
            <label className="form-field" htmlFor="groupSearch">
              <span>Search</span>
              <input id="groupSearch" value={filters.search} onChange={(event) => setFilters((current) => ({ ...current, search: event.target.value }))} placeholder="Group, project, member" />
            </label>
          </div>

          <div className="class-group-sections">
            {[...groupedByClass.values()].map((section) => (
              <section className="class-group-section" key={section.className}>
                <h3>{section.className}</h3>
                <div className="group-card-grid">
                  {section.groups.map((group) => (
                    <GroupCard
                      key={group.id}
                      group={group}
                      onAddMember={setMemberGroup}
                      onLock={handleLock}
                      onManage={setManagedGroup}
                    />
                  ))}
                </div>
              </section>
            ))}
            {visibleGroups.length === 0 ? (
              <div className="empty-state">
                <h3>No groups found</h3>
                <p>Try another class, section, project, or search term.</p>
              </div>
            ) : null}
          </div>
        </>
      ) : null}
    </section>
  )
}

import { useCallback, useEffect, useMemo, useState } from 'react'
import { Link, useNavigate, useParams } from 'react-router-dom'
import { ArrowLeft } from 'lucide-react'
import { USER_ROLES } from '../../auth/constants/roles'
import { useAuth } from '../../auth/hooks/useAuth'
import { ProgressBar } from '../../progress/components/ProgressBar'
import { ProgressMetric } from '../../progress/components/ProgressMetric'
import { ProgressSection } from '../../progress/components/ProgressSection'
import { useProgress } from '../../progress/hooks/useProgress'
import { TaskDetailsModal } from '../../tasks/components/TaskDetailsModal'
import { finalizeGroup, getGroup, getGroupPopQuiz, submitGroupPopQuiz, updateGroupMember } from '../services/groupService'

function normalizeTaskShares(tasks) {
  if (!tasks.length) return []
  const base = Math.floor((100 / tasks.length) * 100) / 100
  let used = 0

  return tasks.map((task, index) => {
    const share = index === tasks.length - 1 ? Math.max(0, Math.round((100 - used) * 100) / 100) : base
    used += share
    return { ...task, share }
  })
}

function completionLabel(completion) {
  return `${completion.completed}/${completion.total} done`
}

export function StudentGroupDetailsPage() {
  const navigate = useNavigate()
  const { groupId } = useParams()
  const { role, user } = useAuth()
  const { error: progressError, isLoading: isProgressLoading, progress } = useProgress()
  const [group, setGroup] = useState(null)
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(true)
  const [selectedTask, setSelectedTask] = useState(null)
  const [notice, setNotice] = useState('')
  const [quiz, setQuiz] = useState(null)
  const [quizAnswers, setQuizAnswers] = useState({})
  const [isFinalizing, setIsFinalizing] = useState(false)
  const [isSubmittingQuiz, setIsSubmittingQuiz] = useState(false)

  const loadGroup = useCallback(async () => {
    setIsLoading(true)
    setError('')
    try {
      setGroup(await getGroup(groupId))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }, [groupId])

  useEffect(() => {
    loadGroup()
  }, [loadGroup])

  useEffect(() => {
    if (role !== USER_ROLES.STUDENT || !groupId || !user?.id) return
    let isMounted = true
    async function loadQuiz() {
      const nextQuiz = await getGroupPopQuiz(groupId).catch(() => null)
      if (isMounted && nextQuiz?.status === 'in_progress') setQuiz((current) => current ?? nextQuiz)
    }
    loadQuiz()
    const timer = window.setInterval(loadQuiz, 5000)
    return () => {
      isMounted = false
      window.clearInterval(timer)
    }
  }, [groupId, role, user?.id])

  const progressGroup = useMemo(
    () => (progress?.groups ?? []).find((item) => item.id === groupId),
    [groupId, progress?.groups],
  )
  const groupTasks = useMemo(
    () => (progress?.tasks ?? []).filter((task) => task.groupId === groupId),
    [groupId, progress?.tasks],
  )
  const myTasks = useMemo(
    () => groupTasks.filter((task) => (task.assignees ?? []).some((assignee) => assignee.userId === user?.id)),
    [groupTasks, user?.id],
  )
  const myTasksWithShare = useMemo(() => normalizeTaskShares(myTasks), [myTasks])
  const myProgress = useMemo(
    () => Math.round(myTasksWithShare.reduce((sum, task) => sum + ((task.progress ?? 0) / 100) * task.share, 0)),
    [myTasksWithShare],
  )
  const taskCompletion = useMemo(() => {
    const completed = groupTasks.filter((task) => task.status === 'done').length
    return {
      completed,
      progress: groupTasks.length ? Math.round((completed / groupTasks.length) * 100) : 0,
      total: groupTasks.length,
    }
  }, [groupTasks])
  const currentMembership = group?.members.find((member) => member.userId === user?.id && member.status === 'active')
  const canManageMembers = role === USER_ROLES.PROFESSOR || Boolean(currentMembership?.isLeader)
  const allTasksDone = taskCompletion.total > 0 && taskCompletion.completed === taskCompletion.total
  const canFinalize = role === USER_ROLES.STUDENT && Boolean(currentMembership?.isLeader) && allTasksDone
  const finalizeHint = !currentMembership?.isLeader
    ? 'Only the group leader can finalize this project.'
    : !allTasksDone ? 'All group tasks must be done before finalizing.' : 'Ready for final quiz.'
  const basePath = role === USER_ROLES.PROFESSOR ? '/professor' : '/student'

  async function makeLeader(member) {
    setNotice('')
    setError('')
    try {
      const updatedGroup = await updateGroupMember(group.id, member.userId, { isLeader: !member.isLeader })
      setGroup(updatedGroup)
      setNotice(member.isLeader ? 'Leader removed.' : 'Leader updated.')
    } catch (updateError) {
      setError(updateError.message)
    }
  }

  function openTask(task) {
    const assignees = task.assignees ?? []
    const isAssignedToMe = assignees.some((assignee) => assignee.userId === user?.id)
    setSelectedTask({
      id: task.id,
      forceReadOnly: assignees.length > 0 && !isAssignedToMe,
    })
  }

  async function finalizeProject() {
    if (!canFinalize) return
    setIsFinalizing(true)
    setError('')
    setNotice('')
    try {
      const result = await finalizeGroup(group.id)
      setGroup(result.group)
      setQuiz(result.quiz)
      setQuizAnswers({})
      setNotice('Project finalized. Complete the pop quiz.')
    } catch (finalizeError) {
      setError(finalizeError.message)
    } finally {
      setIsFinalizing(false)
    }
  }

  function updateQuizAnswer(questionId, selectedOption) {
    setQuizAnswers((current) => ({ ...current, [questionId]: selectedOption }))
  }

  async function submitQuiz(event) {
    event.preventDefault()
    if (!quiz) return
    setIsSubmittingQuiz(true)
    setError('')
    try {
      await submitGroupPopQuiz(group.id, {
        answers: quiz.questions.map((question) => ({
          questionId: question.id,
          selectedOption: quizAnswers[question.id],
        })),
      })
      setQuiz(null)
      setQuizAnswers({})
      setNotice('Pop quiz submitted.')
    } catch (submitError) {
      setError(submitError.message)
    } finally {
      setIsSubmittingQuiz(false)
    }
  }

  if (isLoading || isProgressLoading) return <div className="route-state">Loading group...</div>
  if (error) return <div className="route-state">{error}</div>
  if (!group) return <div className="route-state">Group not found</div>

  return (
    <section className="module-page student-group-details-page">
      <div className="task-detail-breadcrumb">
        <button className="secondary-button" type="button" onClick={() => navigate(`${basePath}/groups`)}>
          <ArrowLeft size={16} aria-hidden="true" />
          Groups
        </button>
        <span>{group.class?.name ?? 'Class'}</span>
      </div>

      <div className="module-header">
        <div>
          <p className="eyebrow">{role === USER_ROLES.PROFESSOR ? 'Professor group' : 'Student group'}</p>
          <h2>{group.name}</h2>
          <p>{group.project?.title ?? 'Project'}</p>
        </div>
        <div className="group-details-actions">
          {group.project?.id ? <Link className="secondary-link-button" to={`${basePath}/projects/${group.project.id}`}>Open project</Link> : null}
        </div>
      </div>

      {notice ? <p className="form-success">{notice}</p> : null}
      {progressError ? <p className="form-error">{progressError}</p> : null}

      {role === USER_ROLES.STUDENT ? (
        <section className="group-finalize-panel">
          <div>
            <h3>Finalize project</h3>
            <p>{finalizeHint}</p>
          </div>
          <button className="primary-button" type="button" disabled={!canFinalize || isFinalizing} onClick={finalizeProject}>
            {isFinalizing ? 'Finalizing...' : 'Finalize project'}
          </button>
        </section>
      ) : null}

      <section className="group-details-members-panel">
        <div className="task-section-heading">
          <h3>Members</h3>
          <span>{group.members.filter((member) => member.status === 'active').length} active members</span>
        </div>
        <div className="group-member-table">
          <div className="group-member-row group-member-head">
            <span>Full name</span>
            <span>Action</span>
          </div>
          {group.members.filter((member) => member.status === 'active').map((member) => (
            <div className="group-member-row" key={member.id}>
              <span>
                {member.displayName}
                {member.isLeader ? <small>Leader</small> : null}
              </span>
              <button
                className="secondary-button"
                type="button"
                disabled={!canManageMembers || member.userId === user?.id}
                onClick={() => makeLeader(member)}
              >
                {member.isLeader ? 'Unset leader' : 'Make leader'}
              </button>
            </div>
          ))}
        </div>
      </section>

      <div className="progress-metric-grid">
        <ProgressMetric label="My progress" value={`${myProgress}%`} hint={`${myTasksWithShare.filter((task) => task.status === 'done').length}/${myTasksWithShare.length} done`} />
        <ProgressMetric label="Group progress" value={`${progressGroup?.progress ?? 0}%`} hint={progressGroup ? completionLabel(progressGroup.taskCompletion) : 'No tasks'} />
        <ProgressMetric label="Task completion" value={`${taskCompletion.progress}%`} hint={completionLabel(taskCompletion)} />
        <ProgressMetric label="Members" value={progressGroup?.memberCount ?? group.members.length} hint="active group members" />
      </div>

      <ProgressSection title="My Group Progress">
        <div className="progress-row-card">
          <div>
            <h4>{group.name}</h4>
            <p>{group.project?.title ?? 'Project'} À {progressGroup?.memberCount ?? group.members.length} members</p>
          </div>
          <ProgressBar label="Group" value={progressGroup?.progress ?? 0} />
        </div>
      </ProgressSection>

      <ProgressSection title="Member Completion">
        <div className="member-progress-grid">
          {(progressGroup?.members ?? []).map((member) => (
            <article className="member-progress-card" key={member.userId}>
              <div>
                <h4>{member.displayName}</h4>
                <p>{member.completedTasks}/{member.totalTasks} tasks À {member.contributionPoints} pts</p>
              </div>
              <ProgressBar label="Member" value={member.progress} />
            </article>
          ))}
        </div>
      </ProgressSection>

      <ProgressSection title="Task Progress">
        <div className="task-progress-table">
          {groupTasks.map((task) => (
            <button className="task-progress-row task-progress-action" type="button" key={task.id} onClick={() => openTask(task)}>
              <div>
                <h4>{task.title}</h4>
                <p>{task.projectTitle} À {task.status}</p>
              </div>
              <ProgressBar label="Task" value={task.progress} />
            </button>
          ))}
          {groupTasks.length === 0 ? <p>No task progress yet.</p> : null}
        </div>
      </ProgressSection>

      {selectedTask ? (
        <TaskDetailsModal
          forceReadOnly={selectedTask.forceReadOnly}
          onClose={() => setSelectedTask(null)}
          taskId={selectedTask.id}
        />
      ) : null}

      {quiz ? (
        <div className="pop-quiz-backdrop">
          <form className="pop-quiz-modal" onSubmit={submitQuiz}>
            <div className="pop-quiz-header">
              <div>
                <p className="eyebrow">Final project check</p>
                <h3>Pop Quiz</h3>
              </div>
            </div>
            <div className="pop-quiz-list">
              {quiz.questions.map((question, index) => (
                <fieldset className="pop-quiz-question" key={question.id}>
                  <legend>{index + 1}. {question.prompt}</legend>
                  <div className="pop-quiz-options">
                    {question.options.map((option) => (
                      <label key={option.key}>
                        <input
                          type="radio"
                          name={`quiz-${question.id}`}
                          value={option.key}
                          checked={quizAnswers[question.id] === option.key}
                          onChange={() => updateQuizAnswer(question.id, option.key)}
                        />
                        <span>{option.key}. {option.label}</span>
                      </label>
                    ))}
                  </div>
                </fieldset>
              ))}
            </div>
            <button className="primary-button" type="submit" disabled={isSubmittingQuiz || Object.keys(quizAnswers).length !== quiz.questions.length}>
              {isSubmittingQuiz ? 'Submitting...' : 'Submit quiz'}
            </button>
          </form>
        </div>
      ) : null}
    </section>
  )
}

import { useCallback, useEffect, useState } from 'react'
import { supabase } from '../../../lib/supabase/client'
import {
  evaluateProjectHealth,
  getProjectHealth,
} from '../services/projectHealthService'

export function useProjectHealth(filters = {}) {
  const [error, setError] = useState('')
  const [health, setHealth] = useState([])
  const [isEvaluating, setIsEvaluating] = useState(false)
  const [isLoading, setIsLoading] = useState(true)

  const loadHealth = useCallback(async () => {
    setIsLoading(true)
    setError('')

    try {
      setHealth(await getProjectHealth(filters))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }, [filters])

  useEffect(() => {
    loadHealth()
  }, [loadHealth])

  useEffect(() => {
    const channel = supabase
      .channel('project-health-dashboard')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'project_health' }, loadHealth)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'health_alerts' }, loadHealth)
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [loadHealth])

  const evaluate = useCallback(async () => {
    setIsEvaluating(true)
    setError('')

    try {
      const next = await evaluateProjectHealth(filters)
      setHealth(next)
      return next
    } catch (evaluateError) {
      setError(evaluateError.message)
      throw evaluateError
    } finally {
      setIsEvaluating(false)
    }
  }, [filters])

  return {
    error,
    evaluate,
    health,
    isEvaluating,
    isLoading,
    loadHealth,
  }
}

import { useCallback, useEffect, useState } from 'react'
import { supabase } from '../../../lib/supabase/client'
import {
  deleteMessage,
  getMessages,
  sendMessage,
  setMessagePin,
} from '../services/messageService'

function upsertMessage(messages, message) {
  const exists = messages.some((item) => item.id === message.id)
  const next = exists
    ? messages.map((item) => item.id === message.id ? message : item)
    : [...messages, message]

  return next.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt))
}

export function useMessages(scope, chatId) {
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [messages, setMessages] = useState([])

  const loadMessages = useCallback(async () => {
    if (!scope || !chatId) {
      setMessages([])
      return
    }

    setIsLoading(true)
    setError('')

    try {
      setMessages(await getMessages(scope, chatId))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }, [chatId, scope])

  useEffect(() => {
    loadMessages()
  }, [loadMessages])

  useEffect(() => {
    if (!scope || !chatId) return undefined

    const messageListener = {
      event: '*',
      schema: 'public',
      table: 'messages',
    }
    if (scope === 'class') messageListener.filter = `class_chat_id=eq.${chatId}`
    if (scope === 'group') messageListener.filter = 'scope=eq.group'

    const channel = supabase
      .channel(`chat:${scope}:${chatId}`)
      .on('postgres_changes', messageListener, loadMessages)
      .on('postgres_changes', {
        event: '*',
        schema: 'public',
        table: 'attachments',
      }, loadMessages)
      .on('postgres_changes', {
        event: '*',
        schema: 'public',
        table: 'pinned_messages',
      }, loadMessages)
      .on('postgres_changes', {
        event: '*',
        schema: 'public',
        table: 'message_deletions',
      }, loadMessages)
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [chatId, loadMessages, scope])

  const send = useCallback(async (payload) => {
    const message = await sendMessage(payload)
    setMessages((current) => upsertMessage(current, message))
    return message
  }, [])

  const remove = useCallback(async (id, mode) => {
    const message = await deleteMessage(id, mode)
    setMessages((current) => (
      mode === 'me'
        ? current.filter((item) => item.id !== id)
        : current.map((item) => item.id === id ? message : item)
    ))
    return message
  }, [])

  const pin = useCallback(async (id, isPinned) => {
    const message = await setMessagePin(id, isPinned)
    await loadMessages()
    return message
  }, [loadMessages])

  return {
    error,
    isLoading,
    loadMessages,
    messages,
    pin,
    remove,
    send,
  }
}

import { useEffect, useMemo, useState } from 'react'
import { useSearchParams } from 'react-router-dom'
import { USER_ROLES } from '../../auth/constants/roles'
import { useAuth } from '../../auth/hooks/useAuth'
import { useClasses } from '../../classes/hooks/useClasses'
import { getClassDetails } from '../../classes/services/classService'
import { useGroups } from '../../groups/hooks/useGroups'
import { ChatComposer } from '../components/ChatComposer'
import { MessageList } from '../components/MessageList'
import { useMessages } from '../hooks/useMessages'

export function MessagesPage() {
  const { role } = useAuth()
  const [searchParams, setSearchParams] = useSearchParams()
  const { classes } = useClasses()
  const { groups } = useGroups()
  const [scope, setScope] = useState(searchParams.get('scope') === 'group' ? 'group' : 'class')
  const [targetId, setTargetId] = useState('')
  const [classChatId, setClassChatId] = useState('')
  const [showPinned, setShowPinned] = useState(false)
  const chatId = scope === 'class' ? classChatId : targetId
  const { error, isLoading, messages, pin, remove, send } = useMessages(scope, chatId)
  const pinnedMessages = messages.filter((message) => message.isPinned)

  const targets = useMemo(() => (
    scope === 'class'
      ? classes.map((item) => ({ id: item.id, name: `${item.name} ${item.section ?? ''}`.trim() }))
      : groups.map((item) => ({ id: item.id, name: item.name }))
  ), [classes, groups, scope])

  useEffect(() => {
    const preselectedClassId = searchParams.get('classId')
    const preselectedGroupId = searchParams.get('groupId')
    const preferredId = scope === 'class' ? preselectedClassId : preselectedGroupId
    const validPreferredId = preferredId && targets.some((target) => target.id === preferredId) ? preferredId : ''
    setTargetId(validPreferredId || (targets[0]?.id ?? ''))
  }, [scope, targets, searchParams])

  useEffect(() => {
    const nextParams = new URLSearchParams(searchParams)
    nextParams.set('scope', scope)
    if (scope === 'class') {
      if (targetId) nextParams.set('classId', targetId)
      nextParams.delete('groupId')
    } else {
      if (targetId) nextParams.set('groupId', targetId)
      nextParams.delete('classId')
    }
    if (nextParams.toString() !== searchParams.toString()) {
      setSearchParams(nextParams, { replace: true })
    }
  }, [scope, targetId, searchParams, setSearchParams])

  useEffect(() => {
    let isMounted = true

    async function loadSelectedChat() {
      setClassChatId('')
      if (scope !== 'class' || !targetId) return

      const details = await getClassDetails(targetId)
      if (isMounted) setClassChatId(details.classChat?.id ?? '')
    }

    loadSelectedChat().catch(() => {
      if (!isMounted) return
      setClassChatId('')
    })

    return () => {
      isMounted = false
    }
  }, [scope, targetId])

  return (
    <section className="module-page">
      <div className="module-header">
        <div>
          <p className="eyebrow">{role}</p>
          <h2>Messages</h2>
          <button type="button" className="secondary-button pinned-chats-button" onClick={() => setShowPinned(true)}>
            Pinned chats ({pinnedMessages.length})
          </button>
        </div>
        <div className="chat-selector">
          <select value={scope} onChange={(event) => setScope(event.target.value)}>
            <option value="class">Class chat</option>
            {role === USER_ROLES.STUDENT ? <option value="group">Group chat</option> : null}
          </select>
          <select value={targetId} onChange={(event) => setTargetId(event.target.value)}>
            {targets.map((target) => <option key={target.id} value={target.id}>{target.name}</option>)}
          </select>
        </div>
      </div>
      {error ? <p className="form-error">{error}</p> : null}
      {isLoading ? <div className="route-state">Loading messages...</div> : null}
      {chatId ? (
        <div className="chat-panel">
          <MessageList messages={messages} onDelete={remove} onPin={pin} />
          <ChatComposer scope={scope} chatId={chatId} onSend={send} />
        </div>
      ) : (
        <div className="empty-state"><h3>No chat selected</h3><p>Select a class or group.</p></div>
      )}

      {showPinned ? (
        <div className="modal-backdrop">
          <div className="modal-panel pinned-modal">
            <div className="task-modal-header">
              <h3>Pinned chats</h3>
              <button className="secondary-button" type="button" onClick={() => setShowPinned(false)}>Close</button>
            </div>
            {pinnedMessages.length === 0 ? (
              <div className="empty-state"><h3>No pinned messages</h3><p>Pin messages from the menu.</p></div>
            ) : (
              <div className="pinned-modal-list">
                {pinnedMessages.map((message) => (
                  <article key={message.id} className="pinned-modal-item">
                    <strong>{message.senderName}</strong>
                    <p>{message.body || message.attachments[0]?.fileName || 'Pinned message'}</p>
                    <small>{new Intl.DateTimeFormat(undefined, { dateStyle: 'medium', timeStyle: 'short' }).format(new Date(message.createdAt))}</small>
                  </article>
                ))}
              </div>
            )}
          </div>
        </div>
      ) : null}
    </section>
  )
}

import { createContext, useCallback, useEffect, useMemo, useState } from 'react'
import { supabase } from '../../../lib/supabase/client'
import { useAuth } from '../../auth/hooks/useAuth'
import {
  getNotifications,
  getUnreadNotificationCount,
  markAllNotificationsRead,
  markNotificationsRead,
} from '../services/notificationService'

export const NotificationContext = createContext(null)

export function NotificationProvider({ children }) {
  const { user } = useAuth()
  const [notifications, setNotifications] = useState([])
  const [unreadCount, setUnreadCount] = useState(0)
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(false)

  const loadNotifications = useCallback(async (filters = {}) => {
    if (!user?.id) return []
    setIsLoading(true)
    setError('')

    try {
      const [items, count] = await Promise.all([
        getNotifications(filters),
        getUnreadNotificationCount(),
      ])
      setNotifications(items)
      setUnreadCount(count)
      return items
    } catch (loadError) {
      setError(loadError.message)
      return []
    } finally {
      setIsLoading(false)
    }
  }, [user?.id])

  useEffect(() => {
    loadNotifications()
  }, [loadNotifications])

  useEffect(() => {
    if (!user?.id) return undefined

    const channel = supabase
      .channel(`notifications:${user.id}`)
      .on('postgres_changes', {
        event: '*',
        schema: 'public',
        table: 'notifications',
        filter: `user_id=eq.${user.id}`,
      }, () => loadNotifications())
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [loadNotifications, user?.id])

  const markRead = useCallback(async (ids) => {
    if (!ids.length) return []
    const updated = await markNotificationsRead(ids)
    setNotifications((current) => current.map((item) => {
      const next = updated.find((notification) => notification.id === item.id)
      return next ?? item
    }))
    setUnreadCount((current) => Math.max(0, current - updated.length))
    return updated
  }, [])

  const markAllRead = useCallback(async () => {
    const updated = await markAllNotificationsRead()
    setNotifications((current) => current.map((item) => ({ ...item, isRead: true, readAt: item.readAt ?? new Date().toISOString() })))
    setUnreadCount(0)
    return updated
  }, [])

  const value = useMemo(() => ({
    error,
    isLoading,
    loadNotifications,
    markAllRead,
    markRead,
    notifications,
    unreadCount,
  }), [error, isLoading, loadNotifications, markAllRead, markRead, notifications, unreadCount])

  return <NotificationContext.Provider value={value}>{children}</NotificationContext.Provider>
}

import { useCallback, useEffect, useState } from 'react'
import {
  acceptPlan,
  generatePlan,
  getGeneratedPlans,
} from '../services/taskGenerationService'

export function useTaskGeneration(projectId, groupId, options = {}) {
  const requiresGroup = Boolean(options.requiresGroup)
  const [error, setError] = useState('')
  const [generations, setGenerations] = useState([])
  const [isGenerating, setIsGenerating] = useState(false)
  const [isLoading, setIsLoading] = useState(false)

  const loadGenerations = useCallback(async () => {
    if (!projectId) return
    if (requiresGroup && !groupId) return
    setIsLoading(true)
    setError('')

    try {
      setGenerations(await getGeneratedPlans(projectId, groupId))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }, [groupId, projectId, requiresGroup])

  useEffect(() => {
    loadGenerations()
  }, [loadGenerations])

  const generate = useCallback(async () => {
    setIsGenerating(true)
    setError('')

    try {
      const generation = await generatePlan({ projectId, groupId, mode: 'draft' })
      setGenerations((current) => [generation, ...current])
      return generation
    } catch (generateError) {
      setError(generateError.message)
      throw generateError
    } finally {
      setIsGenerating(false)
    }
  }, [groupId, projectId])

  const accept = useCallback(async (id, mode, tasks) => {
    const generation = await acceptPlan(id, mode, tasks)
    setGenerations((current) => current.map((item) => item.id === id ? generation : item))
    return generation
  }, [])

  return {
    accept,
    error,
    generate,
    generations,
    isGenerating,
    isLoading,
    loadGenerations,
  }
}

