  const [isLoading, setIsLoading] = useState(true)

  const loadProjects = useCallback(async () => {
    setIsLoading(true)
    setError('')

    try {
      setProjects(await getProjects())
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }, [])

  useEffect(() => {
