import { useEffect, useState } from 'react'
import { Download, File, FileImage, FileText, Film, Trash2 } from 'lucide-react'
import { getVersionDownloadUrl } from '../../submissions/services/submissionService'

function iconFor(mimeType = '') {
  if (mimeType.startsWith('image/')) return FileImage
  if (mimeType.startsWith('video/')) return Film
  if (mimeType.includes('pdf') || mimeType.includes('document') || mimeType.includes('word')) return FileText
  return File
}

function formatSize(bytes) {
  if (!bytes) return '0 B'
  const mb = bytes / (1024 * 1024)
  return mb >= 1 ? `${mb.toFixed(1)} MB` : `${Math.round(bytes / 1024)} KB`
}

function previewType(mimeType = '') {
  if (mimeType.startsWith('image/')) return 'image'
  if (mimeType.startsWith('video/')) return 'video'
  if (mimeType.includes('pdf')) return 'pdf'
  return 'file'
}

export function TaskAttachmentPreview({ canManage = false, onDelete, version }) {
  const Icon = iconFor(version.mimeType)
  const [url, setUrl] = useState('')
  const type = previewType(version.mimeType)

  useEffect(() => {
    let isMounted = true

    getVersionDownloadUrl(version.id)
      .then((signedUrl) => {
        if (isMounted) setUrl(signedUrl)
      })
      .catch(() => {
        if (isMounted) setUrl('')
      })

    return () => {
      isMounted = false
    }
  }, [version.id])

  function downloadFile() {
    if (url) window.open(url, '_blank', 'noopener,noreferrer')
  }

  return (
    <article className={`task-file-paper ${version.isFinal ? 'is-current' : ''}`}>
      <div className="task-file-preview">
        {type === 'image' && url ? <img src={url} alt={version.fileName} loading="lazy" /> : null}
        {type === 'video' && url ? <video src={url} muted preload="metadata" /> : null}
        {type === 'pdf' && url ? <iframe src={`${url}#toolbar=0&navpanes=0`} title={version.fileName} /> : null}
        {(!url || type === 'file') ? <Icon size={28} aria-hidden="true" /> : null}
      </div>
      <div className="task-file-caption">
        <strong title={version.fileName}>{version.fileName}</strong>
        <span>v{version.version}</span>
        <small>{formatSize(version.fileSizeBytes)}</small>
      </div>
      <div className="task-file-actions">
        <button type="button" onClick={downloadFile} disabled={!url} aria-label={`Download ${version.fileName}`}>
          <Download size={14} aria-hidden="true" />
        </button>
        {canManage ? (
          <button type="button" onClick={() => window.confirm('Delete this attachment?') && onDelete?.(version.id)} aria-label={`Delete ${version.fileName}`}>
            <Trash2 size={14} aria-hidden="true" />
          </button>
        ) : null}
      </div>
    </article>
  )
}

import { useEffect, useMemo, useState } from 'react'
import { Check, Pencil, X } from 'lucide-react'
import { USER_ROLES } from '../../auth/constants/roles'

function formatDate(value) {
  return value ? new Intl.DateTimeFormat(undefined, { dateStyle: 'medium' }).format(new Date(value)) : 'No deadline'
}

function flattenMembers(groups, groupId) {
  return groups.find((group) => group.id === groupId)?.members?.filter((member) => member.status === 'active') ?? []
}

function progressForStatus(status) {
  return {
    todo: 0,
    blocked: 0,
    in_progress: 25,
    review: 50,
    done: 100,
  }[status] ?? 0
}

function toDateTimeInput(value) {
  if (!value) return ''
  const date = new Date(value)
  const localDate = new Date(date.getTime() - date.getTimezoneOffset() * 60000)
  return localDate.toISOString().slice(0, 16)
}

function fromDateTimeInput(value) {
  return value ? new Date(value).toISOString() : null
}

function CommentBox({ comments, onSubmit }) {
  const [body, setBody] = useState('')
  const [expanded, setExpanded] = useState(false)
  const visible = expanded ? comments : comments.slice(-3)

  async function submit(event) {
    event.preventDefault()
    if (!body.trim()) return
    await onSubmit(body.trim())
    setBody('')
  }

  return (
    <div className="task-comments-compact">
      <div className="task-comments-header">
        <p className="eyebrow">Comments</p>
        {comments.length > 3 ? (
          <button type="button" onClick={() => setExpanded((current) => !current)}>
            {expanded ? 'Collapse' : `Load ${comments.length - 3} more`}
          </button>
        ) : null}
      </div>
      {visible.map((comment) => (
        <p className="task-comment-line" key={comment.id}>
          <strong>{comment.displayName}</strong>
          <span>{comment.body}</span>
        </p>
      ))}
      <form className="task-comment-form" onSubmit={submit}>
        <input aria-label="Comment" value={body} onChange={(event) => setBody(event.target.value)} placeholder="Add a comment" />
        <button className="secondary-button" type="submit">Post</button>
      </form>
    </div>
  )
}

export function TaskCard({ currentUserId, depth = 0, groups, onComment, onDelete, onOpen, onUpdate, role, task }) {
  const [isExpanded, setIsExpanded] = useState(false)
  const [draftProgress, setDraftProgress] = useState(task.progress ?? 0)
  const [status, setStatus] = useState(task.status)
  const [isSaving, setIsSaving] = useState(false)
  const [saveError, setSaveError] = useState('')
  const [isEditing, setIsEditing] = useState(false)
  const [isEditSaving, setIsEditSaving] = useState(false)
  const [editError, setEditError] = useState('')
  const [editForm, setEditForm] = useState({
    description: task.description ?? '',
    dueAt: toDateTimeInput(task.dueAt),
    title: task.title ?? '',
  })
  const assigneeIds = task.assignments.map((assignment) => assignment.assigneeId)
  const hasAssignees = assigneeIds.length > 0
  const isAssignedToMe = Boolean(currentUserId && assigneeIds.includes(currentUserId))
  const canUpdateStatus = isAssignedToMe || !hasAssignees
  const isProfessor = role === USER_ROLES.PROFESSOR
  const isMainTask = task.taskType === 'main' || (!task.parentTaskId && task.children?.length > 0)
  const members = useMemo(() => flattenMembers(groups, task.groupId), [groups, task.groupId])
  const assignedNames = useMemo(() => {
    if (!task.assignments.length) return []
    const byId = new Map(members.map((member) => [member.userId, member.displayName]))
    return task.assignments.map((assignment) => byId.get(assignment.assigneeId) ?? assignment.displayName ?? assignment.email ?? 'Unknown member')
  }, [members, task.assignments])

  useEffect(() => {
    setStatus(task.status)
    setDraftProgress(task.progress ?? 0)
  }, [task.progress, task.status])

  useEffect(() => {
    if (isEditing) return
    setEditForm({
      description: task.description ?? '',
      dueAt: toDateTimeInput(task.dueAt),
      title: task.title ?? '',
    })
  }, [isEditing, task.description, task.dueAt, task.title])

  function updateEditField(event) {
    const { name, value } = event.target
    setEditForm((current) => ({ ...current, [name]: value }))
  }

  function cancelEdit() {
    setIsEditing(false)
    setEditError('')
    setEditForm({
      description: task.description ?? '',
      dueAt: toDateTimeInput(task.dueAt),
      title: task.title ?? '',
    })
  }

  async function saveEdits(event) {
    event.preventDefault()
    const title = editForm.title.trim()
    if (!title) {
      setEditError('Title is required')
      return
    }

    setIsEditSaving(true)
    setEditError('')
    try {
      await onUpdate(task.id, {
        description: editForm.description.trim() || null,
        dueAt: fromDateTimeInput(editForm.dueAt),
        title,
      })
      setIsEditing(false)
    } catch (error) {
      setEditError(error.message ?? 'Failed to save task')
    } finally {
      setIsEditSaving(false)
    }
  }

  function changeStatus(nextStatus) {
    const nextProgress = progressForStatus(nextStatus)
    setStatus(nextStatus)
    setDraftProgress(nextProgress)
  }

  async function persistStatus(nextStatus) {
    setIsSaving(true)
    setSaveError('')
    try {
      await onUpdate(task.id, { status: nextStatus })
    } catch (error) {
      setSaveError(error.message ?? 'Failed to save status')
      throw error
    } finally {
      setIsSaving(false)
    }
  }

  async function saveTaskProgress() {
    await persistStatus(status)
  }

  async function handleStatusChange(nextStatus) {
    changeStatus(nextStatus)
    try {
      await persistStatus(nextStatus)
    } catch {
      setStatus(task.status)
      setDraftProgress(task.progress ?? 0)
    }
  }

  async function claimTask() {
    if (!currentUserId || hasAssignees) return
    setIsSaving(true)
    setSaveError('')
    try {
      await onUpdate(task.id, { assigneeIds: [currentUserId] })
    } catch (error) {
      setSaveError(error.message ?? 'Unable to claim task')
    } finally {
      setIsSaving(false)
    }
  }

  async function archiveTask() {
    if (window.confirm(`Archive "${task.title}"?`)) await onUpdate(task.id, { archived: true })
  }

  async function deleteTask() {
    if (window.confirm(`Delete "${task.title}"?`)) await onDelete(task.id)
  }

  const editButton = (
    <button className="icon-button task-edit-button" type="button" onClick={() => setIsEditing(true)} aria-label={`Edit ${task.title}`}>
      <Pencil size={16} aria-hidden="true" />
    </button>
  )

  const editFormMarkup = (
    <form className="task-edit-form" onSubmit={saveEdits}>
      <label className="form-field" htmlFor={`task-title-${task.id}`}>
        <span>Title</span>
        <input id={`task-title-${task.id}`} name="title" value={editForm.title} onChange={updateEditField} maxLength={180} required />
      </label>
      <label className="form-field" htmlFor={`task-description-${task.id}`}>
        <span>Description</span>
        <textarea id={`task-description-${task.id}`} name="description" value={editForm.description} onChange={updateEditField} maxLength={5000} rows={3} />
      </label>
      <label className="form-field" htmlFor={`task-due-${task.id}`}>
        <span>Deadline</span>
        <input id={`task-due-${task.id}`} name="dueAt" type="datetime-local" value={editForm.dueAt} onChange={updateEditField} />
      </label>
      {editError ? <p className="form-error">{editError}</p> : null}
      <div className="task-edit-actions">
        <button className="icon-button task-edit-save" type="submit" disabled={isEditSaving} aria-label="Save task edits">
          <Check size={16} aria-hidden="true" />
        </button>
        <button className="icon-button" type="button" onClick={cancelEdit} disabled={isEditSaving} aria-label="Cancel task edits">
          <X size={16} aria-hidden="true" />
        </button>
      </div>
    </form>
  )

  if (isMainTask) {
    return (
      <section className="main-task-section">
        <div className="main-task-heading">
          {isEditing ? editFormMarkup : (
            <div>
              <p className="eyebrow">Main task</p>
              <h2>{task.title}</h2>
              {task.description ? <p>{task.description}</p> : null}
              <small>{formatDate(task.dueAt)}</small>
            </div>
          )}
          <div className="task-heading-actions">
            {!isEditing ? editButton : null}
            {isProfessor ? <button className="danger-button" type="button" onClick={archiveTask}>Archive</button> : null}
          </div>
        </div>
        <div className="task-children compact">
          {task.children.map((child) => (
          <TaskCard
            currentUserId={currentUserId}
            key={child.id}
            depth={depth + 1}
            groups={groups}
              task={child}
              role={role}
              onComment={onComment}
              onDelete={onDelete}
              onOpen={onOpen}
              onUpdate={onUpdate}
            />
          ))}
        </div>
      </section>
    )
  }

  return (
    <article className={`task-card compact-task-card depth-${depth}`}>
      <div className="task-card-top">
        {isEditing ? editFormMarkup : (
          <button className="task-card-summary" type="button" onClick={() => setIsExpanded((current) => !current)}>
            <span className={`task-priority priority-${String(task.priority || '').toLowerCase()}`}>{task.priority}</span>
            <strong>{task.title}</strong>
            <small>{task.description || 'No description'}</small>
          </button>
        )}
        {!isEditing ? editButton : null}
      </div>
      <div className="task-card-meta">
        <span>{formatDate(task.dueAt)}</span>
        <span>{status}</span>
        <span>{task.groupScoreWeight ?? 0}% pts</span>
        <span>{task.comments.length} comments</span>
        <button className="task-open-link" type="button" onClick={() => onOpen?.(task.id)}>Open</button>
      </div>
      <div className="task-progress-meter">
        <div className="progress-track"><span style={{ width: `${draftProgress}%` }} /></div>
        <strong>{draftProgress}%</strong>
      </div>

      {isExpanded ? (
        <div className="task-card-details">
          <dl className="compact-details">
            <div><dt>Group</dt><dd>{task.group?.name ?? 'Group'}</dd></div>
            <div>
              <dt>{isProfessor ? 'Assigned to' : 'Owners'}</dt>
              <dd>
                {isProfessor
                  ? (assignedNames.length ? assignedNames.join(', ') : 'Not assigned to anyone yet.')
                  : (assignedNames.length ? assignedNames.join(', ') : 'Not claimed yet')}
              </dd>
            </div>
            <div><dt>My progress</dt><dd>{task.memberScoreWeight ?? 0}%</dd></div>
          </dl>

          {!isProfessor ? (
            <>
              <div className="task-controls task-controls-single">
                <label className="form-field" htmlFor={`status-${task.id}`}>
                  <span>Status</span>
                  <select
                    id={`status-${task.id}`}
                    value={status}
                    onChange={(event) => handleStatusChange(event.target.value)}
                    disabled={isSaving || !canUpdateStatus}
                  >
                    <option value="todo">Todo</option>
                    <option value="in_progress">In progress</option>
                    <option value="review">Review</option>
                    <option value="done">Done</option>
                    <option value="blocked">Blocked</option>
                  </select>
                </label>
              </div>
              <button className="primary-button" type="button" onClick={saveTaskProgress} disabled={isSaving || !canUpdateStatus}>
                {isSaving ? 'Saving...' : 'Save status'}
              </button>
              {!canUpdateStatus ? <p className="form-error">Only assigned owners can update this task status.</p> : null}
              {saveError ? <p className="form-error">{saveError}</p> : null}

              <div className="task-assignees task-owner-panel">
                <p className="eyebrow">Owners</p>
                {assignedNames.length ? (
                  <p className="task-owner-names">{assignedNames.join(', ')}</p>
                ) : (
                  <>
                    <p className="task-owner-names">No owner yet. Any active group member can claim this task.</p>
                    <button className="secondary-button" type="button" onClick={claimTask} disabled={isSaving || !currentUserId}>
                      {isSaving ? 'Claiming...' : 'Claim task'}
                    </button>
                  </>
                )}
              </div>
            </>
          ) : null}

          <CommentBox comments={task.comments} onSubmit={(body) => onComment(task.id, { body })} />

          <div className="card-actions">
            <button className="secondary-button" type="button" onClick={() => onOpen?.(task.id)}>Open</button>
            {isProfessor ? <button className="danger-button" type="button" onClick={archiveTask}>Archive</button> : null}
            {!isProfessor ? <button className="danger-button" type="button" onClick={deleteTask}>Delete</button> : null}
          </div>
        </div>
      ) : null}
    </article>
  )
}

import { Link } from 'react-router-dom'
import { useEffect, useState } from 'react'
import { X } from 'lucide-react'
import { USER_ROLES } from '../../auth/constants/roles'
import { createReassignment } from '../../reassignments/services/reassignmentService'
import { getGroup } from '../../groups/services/groupService'
import { TaskActivityPanel } from './TaskActivityPanel'
import { TaskAttachmentPreview } from './TaskAttachmentPreview'
import { TaskAttachmentUploader } from './TaskAttachmentUploader'
import { TaskVersionTable } from './TaskVersionTable'

function formatDate(value) {
  return value ? new Intl.DateTimeFormat(undefined, { dateStyle: 'medium', timeStyle: 'short' }).format(new Date(value)) : 'No deadline'
}

function progressForStatus(status) {
  return {
    todo: 0,
    blocked: 0,
    in_progress: 25,
    review: 50,
    done: 100,
  }[status] ?? 0
}

function assigneeNames(assignments = []) {
  return assignments.map((assignment) => assignment.displayName).filter(Boolean)
}

function ReassignmentModal({ currentAssignment, onClose, task }) {
  const [error, setError] = useState('')
  const [form, setForm] = useState({
    reason: '',
    requestedAssigneeId: '',
    scorePolicy: 'keep_original',
  })
  const [isLoading, setIsLoading] = useState(false)
  const [members, setMembers] = useState([])

  async function loadMembers() {
    if (members.length || isLoading) return
    setIsLoading(true)
    setError('')
    try {
      const group = await getGroup(task.groupId)
      const activeMembers = (group.members ?? []).filter((member) => member.status === 'active' && member.userId !== currentAssignment.assigneeId)
      setMembers(activeMembers)
      setForm((current) => ({ ...current, requestedAssigneeId: activeMembers[0]?.userId ?? '' }))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    loadMembers()
  }, [])

  async function handleSubmit(event) {
    event.preventDefault()
    setError('')
    setIsLoading(true)
    try {
      await createReassignment({
        currentAssigneeId: currentAssignment.assigneeId,
        reason: form.reason,
        requestedAssigneeId: form.requestedAssigneeId,
        scorePolicy: form.scorePolicy,
        taskId: task.id,
      })
      onClose('Reassignment requested.')
    } catch (submitError) {
      setError(submitError.message)
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="modal-backdrop">
      <form className="modal-panel task-reassignment-modal" onSubmit={handleSubmit}>
        <div className="task-section-heading">
          <div>
            <p className="eyebrow">Task reassignment</p>
            <h3>Request reassignment</h3>
          </div>
          <button className="secondary-button" type="button" onClick={() => onClose()}>Close</button>
        </div>
        <label className="form-field">
          <span>Current assignee</span>
          <input value={currentAssignment.displayName ?? currentAssignment.email ?? 'Current assignee'} readOnly />
        </label>
        <label className="form-field" htmlFor="taskDetailRequestedAssignee">
          <span>New assignee</span>
          <select id="taskDetailRequestedAssignee" required value={form.requestedAssigneeId} onFocus={loadMembers} onChange={(event) => setForm((current) => ({ ...current, requestedAssigneeId: event.target.value }))}>
            {members.map((member) => (
              <option key={member.userId} value={member.userId}>{member.displayName}</option>
            ))}
          </select>
        </label>
        <label className="form-field" htmlFor="taskDetailScorePolicy">
          <span>Score handling</span>
          <select id="taskDetailScorePolicy" value={form.scorePolicy} onChange={(event) => setForm((current) => ({ ...current, scorePolicy: event.target.value }))}>
            <option value="keep_original">Keep original score</option>
            <option value="split_50_50">Split score 50/50</option>
            <option value="full_transfer">Full transfer</option>
          </select>
        </label>
        <label className="form-field" htmlFor="taskDetailReassignmentReason">
          <span>Reason</span>
          <textarea id="taskDetailReassignmentReason" required rows="4" value={form.reason} onChange={(event) => setForm((current) => ({ ...current, reason: event.target.value }))} />
        </label>
        {!isLoading && members.length === 0 ? <p className="muted-copy">No other group members available.</p> : null}
        {error ? <p className="form-error">{error}</p> : null}
        <button className="primary-button" type="submit" disabled={isLoading || !form.requestedAssigneeId}>
          {isLoading ? 'Submitting...' : 'Request reassignment'}
        </button>
      </form>
    </div>
  )
}

export function TaskDetailsContent({
  actions,
  backPath,
  details,
  forceReadOnly = false,
  isModal = false,
  onClose,
  role,
  user,
}) {
  const [reassignmentNotice, setReassignmentNotice] = useState('')
  const [showReassignment, setShowReassignment] = useState(false)
  const { history, submission, task } = details
  const assignments = task.assignments ?? []
  const currentAssignment = assignments.find((assignment) => assignment.assigneeId === user?.id)
  const names = assigneeNames(assignments)
  const hasAssignees = assignments.length > 0
  const isAssignedToMe = assignments.some((assignment) => assignment.assigneeId === user?.id)
  const isProfessor = role === USER_ROLES.PROFESSOR
  const canUpload = role === USER_ROLES.STUDENT && !forceReadOnly && (isAssignedToMe || !hasAssignees)
  const canUpdateStatus = role === USER_ROLES.STUDENT && !forceReadOnly && (isAssignedToMe || !hasAssignees)
  const activeVersions = submission?.versions ?? []
  const currentVersion = activeVersions.find((version) => version.isFinal) ?? activeVersions[0]
  const visibleVersions = (isProfessor || forceReadOnly)
    ? activeVersions.filter((version) => version.isFinal)
    : [currentVersion, ...activeVersions.filter((version) => version.id !== currentVersion?.id).slice(0, 3)].filter(Boolean)

  return (
    <div className={isModal ? 'task-detail-modal-shell' : 'task-detail-layout'}>
      <main className="task-detail-main">
        {isModal ? (
          <button className="task-detail-modal-close" type="button" onClick={onClose} aria-label="Close task details">
            <X size={18} aria-hidden="true" />
          </button>
        ) : null}

        <div className="task-detail-titlebar">
          <div>
            <p className="eyebrow">{task.priority} priority</p>
            <h2>{task.title}</h2>
            <p>{task.description || 'No description provided.'}</p>
          </div>
        </div>

        <section className="task-detail-section">
          <div className="task-section-heading">
            <h3>Attachments</h3>
            {!isProfessor && !forceReadOnly ? (
              <TaskAttachmentUploader
                canUpload={canUpload}
                onUpload={actions.uploadVersion}
                taskId={task.id}
                userId={user?.id}
              />
            ) : null}
          </div>
          <div className="task-paper-grid">
            {visibleVersions.map((version) => (
              <TaskAttachmentPreview canManage={!isProfessor && !forceReadOnly && canUpload} key={version.id} onDelete={actions.deleteVersion} version={version} />
            ))}
            {!visibleVersions.length ? <p className="muted-copy">{isProfessor || forceReadOnly ? 'No final file selected yet.' : 'No files attached yet.'}</p> : null}
          </div>
        </section>

        {!isProfessor && !forceReadOnly ? (
          <section className="task-detail-section">
            <div className="task-section-heading">
              <h3>File versions</h3>
              {submission ? <span>{activeVersions.length} active versions</span> : <span>No submission yet</span>}
            </div>
            <TaskVersionTable
              onArchive={actions.archiveVersion}
              onDelete={actions.deleteVersion}
              onSelectCurrent={actions.selectCurrent}
              submission={submission}
            />
          </section>
        ) : null}

        <TaskActivityPanel comments={task.comments} history={history} onComment={actions.comment} />
      </main>

      <aside className="task-detail-sidebar">
        <label className="form-field" htmlFor={`taskDetailStatus-${task.id}`}>
          <span>Status</span>
          <select id={`taskDetailStatus-${task.id}`} value={task.status} onChange={(event) => actions.saveStatus(event.target.value)} disabled={!canUpdateStatus}>
            <option value="todo">Todo</option>
            <option value="in_progress">In progress</option>
            <option value="review">Review</option>
            <option value="done">Done</option>
            <option value="blocked">Blocked</option>
          </select>
        </label>
        <dl className="task-detail-meta">
          <div><dt>Assigned to</dt><dd>{names.length ? names.join(', ') : 'Not assigned to anyone yet.'}</dd></div>
          <div><dt>Deadline</dt><dd>{formatDate(task.dueAt)}</dd></div>
          <div><dt>Progress</dt><dd>{progressForStatus(task.status)}%</dd></div>
          <div><dt>Points</dt><dd>{task.groupScoreWeight ?? 0}%</dd></div>
          <div><dt>Class</dt><dd>{task.group?.className ?? 'Class'}</dd></div>
        </dl>
        {role === USER_ROLES.STUDENT && !forceReadOnly && currentAssignment ? (
          <button className="secondary-button" type="button" onClick={() => setShowReassignment(true)}>Request reassignment</button>
        ) : null}
        {reassignmentNotice ? <p className="form-success">{reassignmentNotice}</p> : null}
        {!isModal ? <Link className="secondary-link-button" to={backPath}>Back to tasks</Link> : null}
      </aside>
      {showReassignment ? (
        <ReassignmentModal
          currentAssignment={currentAssignment}
          onClose={(notice) => {
            setShowReassignment(false)
            if (notice) setReassignmentNotice(notice)
          }}
          task={task}
        />
      ) : null}
    </div>
  )
}

import { useCallback, useEffect, useState } from 'react'
import { addTaskComment, getTaskDetails, updateTask } from '../services/taskService'
import {
  archiveSubmissionVersion,
  createSubmissionVersion,
  deleteSubmissionVersion,
  selectFinalVersion,
} from '../../submissions/services/submissionService'

export function useTaskDetails(taskId) {
  const [details, setDetails] = useState(null)
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(true)

  const loadDetails = useCallback(async () => {
    setIsLoading(true)
    setError('')
    try {
      setDetails(await getTaskDetails(taskId))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      setIsLoading(false)
    }
  }, [taskId])

  useEffect(() => {
    loadDetails()
  }, [loadDetails])

  const saveStatus = useCallback(async (status) => {
    await updateTask(taskId, { status })
    await loadDetails()
  }, [loadDetails, taskId])

  const comment = useCallback(async (payload) => {
    await addTaskComment(taskId, payload)
    await loadDetails()
  }, [loadDetails, taskId])

  const uploadVersion = useCallback(async (payload) => {
    const submission = await createSubmissionVersion(payload)
    setDetails((current) => current ? { ...current, submission } : current)
    return submission
  }, [])

  const selectCurrent = useCallback(async (submissionId, versionId) => {
    const submission = await selectFinalVersion(submissionId, versionId)
    setDetails((current) => current ? { ...current, submission } : current)
    return submission
  }, [])

  const archiveVersion = useCallback(async (versionId) => {
    const submission = await archiveSubmissionVersion(versionId)
    setDetails((current) => current ? { ...current, submission } : current)
    return submission
  }, [])

  const deleteVersion = useCallback(async (versionId) => {
    const submission = await deleteSubmissionVersion(versionId)
    setDetails((current) => current ? { ...current, submission } : current)
    return submission
  }, [])

  return {
    archiveVersion,
    comment,
    deleteVersion,
    details,
    error,
    isLoading,
    loadDetails,
    saveStatus,
    selectCurrent,
    uploadVersion,
  }
}

import { useCallback, useEffect, useRef, useState } from 'react'
import { supabase } from '../../../lib/supabase/client'
import {
  addTaskComment,
  createTask,
  deleteTask,
  getTasks,
  updateTask,
} from '../services/taskService'

function replaceTask(tasks, nextTask) {
  return tasks.map((task) => {
    if (task.id === nextTask.id) return { ...nextTask, children: task.children ?? nextTask.children ?? [] }
    return {
      ...task,
      children: replaceTask(task.children ?? [], nextTask),
    }
  })
}

export function useTasks(filters) {
  const [tasks, setTasks] = useState([])
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(true)
  const refreshTimerRef = useRef(null)

  const loadTasks = useCallback(async ({ silent = false } = {}) => {
    if (!silent) setIsLoading(true)
    setError('')

    try {
      setTasks(await getTasks(filters))
    } catch (loadError) {
      setError(loadError.message)
    } finally {
      if (!silent) setIsLoading(false)
    }
  }, [filters])

  const refreshTasksSilently = useCallback(async () => {
    await loadTasks({ silent: true })
  }, [loadTasks])

  useEffect(() => {
    loadTasks()
  }, [loadTasks])

  useEffect(() => {
    const scheduleRefresh = () => {
      if (refreshTimerRef.current) clearTimeout(refreshTimerRef.current)
      refreshTimerRef.current = setTimeout(() => {
        refreshTasksSilently()
      }, 150)
    }

    const channel = supabase
      .channel(`tasks-live:${filters.groupId ?? 'all'}:${filters.projectId ?? 'all'}`)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'tasks' }, scheduleRefresh)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'task_assignments' }, scheduleRefresh)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'task_comments' }, scheduleRefresh)
      .subscribe()

    return () => {
      if (refreshTimerRef.current) clearTimeout(refreshTimerRef.current)
      supabase.removeChannel(channel)
    }
  }, [filters.groupId, filters.projectId, refreshTasksSilently])

  const add = useCallback(async (payload) => {
    const task = await createTask(payload)
    await loadTasks({ silent: true })
    return task
  }, [loadTasks])

  const save = useCallback(async (id, payload) => {
    const task = await updateTask(id, payload)
    setTasks((current) => replaceTask(current, task))
    await loadTasks({ silent: true })
    return task
  }, [loadTasks])

  const remove = useCallback(async (id) => {
    const result = await deleteTask(id)
    await loadTasks({ silent: true })
    return result
  }, [loadTasks])

  const comment = useCallback(async (id, payload) => {
    const task = await addTaskComment(id, payload)
    setTasks((current) => replaceTask(current, task))
    return task
  }, [])

  return {
    add,
    comment,
    error,
    isLoading,
    loadTasks,
    remove,
    save,
    tasks,
  }
}

import { env } from '../../config/env'
import { supabase } from '../../lib/supabase/client'

async function getAccessToken() {
  const { data, error } = await supabase.auth.getSession()
  if (error) throw error
  return data.session?.access_token
}

export async function apiRequest(path, options = {}) {
  const token = await getAccessToken()
  const headers = new Headers(options.headers)
  const controller = new AbortController()
  const timeoutMs = 45000
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs)

  headers.set('Content-Type', 'application/json')

  if (token) {
    headers.set('Authorization', `Bearer ${token}`)
  }

  let response
  try {
    response = await fetch(`${env.apiBaseUrl}${path}`, {
      ...options,
      headers,
      signal: controller.signal,
    })
  } catch (error) {
    if (error.name === 'AbortError') {
      throw new Error('Request timed out. Try shortening the description or retrying.')
    }
    throw error
  } finally {
    clearTimeout(timeoutId)
  }

  const payload = await response.json().catch(() => ({}))

  if (!response.ok) {
    const details = payload.error?.details
    const readableDetails = typeof details === 'string'
      ? details
      : details?.formErrors?.[0]
        ?? Object.values(details?.fieldErrors ?? {}).flat().filter(Boolean)[0]
        ?? null
    throw new Error(readableDetails ?? payload.error?.message ?? 'Request failed')
  }

  return payload
}
